import{_ as t,o as s,c as r,af as a}from"./chunks/framework.BSym9njW.js";const n="/hello-rocm/assets/01-login-page.N0ZXebhq.webp",o="/hello-rocm/assets/02-login-methods.2rT64ilL.webp",i="/hello-rocm/assets/03-github-login.DIlU6mRu.webp",l="/hello-rocm/assets/04-jupyterhub-home-1.Dm5D0bs5.webp",d="/hello-rocm/assets/05-jupyterhub-home-2.b9yBdJGQ.webp",p="/hello-rocm/assets/06-available-resources-1.CZqVsNhi.webp",h="/hello-rocm/assets/07-available-resources-2.DCoKI9sd.webp",c="/hello-rocm/assets/08-code-server-select.qunjALjY.webp",u="/hello-rocm/assets/09-code-server-launch.Ce-RX4vn.webp",g="/hello-rocm/assets/10-port-forward-1.BClQEl_W.webp",b="/hello-rocm/assets/11-port-forward-2.Dvs7kY13.webp",m="/hello-rocm/assets/12-port-forward-url.C0BwjWhj.webp",k="/hello-rocm/assets/13-install-extension.zSI41RKD.webp",v="/hello-rocm/assets/14-exit-hub-control-panel.spuBCUFm.webp",C="/hello-rocm/assets/16-code-server-back-home.BbvoHb86.webp",y="/hello-rocm/assets/15-stop-my-server.BqQP4cMc.webp",x=JSON.parse('{"title":"AUP Learning Cloud","description":"AUP Learning Cloud 远程 JupyterHub/Code Server 使用指南与登录入口","frontmatter":{"title":"AUP Learning Cloud","description":"AUP Learning Cloud 远程 JupyterHub/Code Server 使用指南与登录入口"},"headers":[],"relativePath":"zh/cloud/aup-learning-cloud.md","filePath":"zh/cloud/aup-learning-cloud.md","lastUpdated":1784269398000}'),P={name:"zh/cloud/aup-learning-cloud.md"};function _(A,e,S,f,D,q){return s(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="☁️-aup-learning-cloud-·-端侧-amd-算力" tabindex="-1">☁️ AUP Learning Cloud · 端侧 AMD 算力 <a class="header-anchor" href="#☁️-aup-learning-cloud-·-端侧-amd-算力" aria-label="Permalink to &quot;☁️ AUP Learning Cloud · 端侧 AMD 算力&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">🧪 内测阶段公告</p><p><strong>AUP Learning Cloud 目前处于内部测试阶段</strong>，平台功能、资源配额与计费规则可能随时调整；如遇服务不稳定或异常，请及时向管理员反馈。正式开放时间与相关政策以官方通知为准。</p></div><blockquote><p>基于 <strong>AMD 端侧 Ryzen™ AI APU</strong> 构建的远程 <strong>JupyterHub / Code Server</strong> 开发环境，无需本地配置，浏览器登录即可上手 ROCm 实战。</p></blockquote><div class="tip custom-block"><p class="custom-block-title">📦 开源项目</p><p><a href="https://github.com/AMDResearch/aup-learning-cloud" target="_blank" rel="noreferrer"><strong>AUP Learning Cloud</strong></a> 是 <strong>AMD Research</strong> 开源的定制化 JupyterHub 学习云平台（<strong>MIT 许可</strong>），面向 AMD 硬件加速（CPU / GPU / NPU），内置计算机视觉、深度学习、大模型、物理仿真等实践课程工具包，并基于 Kubernetes（K3s）部署。源码、部署方式与镜像均公开在 GitHub：<a href="https://github.com/AMDResearch/aup-learning-cloud" target="_blank" rel="noreferrer">https://github.com/AMDResearch/aup-learning-cloud</a>。</p></div><h2 id="🖥-平台设备说明" tabindex="-1">🖥 平台设备说明 <a class="header-anchor" href="#🖥-平台设备说明" aria-label="Permalink to &quot;🖥 平台设备说明&quot;">​</a></h2><p><a href="https://github.com/AMDResearch/aup-learning-cloud" target="_blank" rel="noreferrer"><strong>AUP Learning Cloud</strong></a> 的算力全部来自 <strong>AMD 端侧（client）Ryzen™ AI APU</strong>。与独立显卡方案不同，这里的 <strong>CPU / GPU / NPU 集成在同一颗芯片上</strong>，更贴近真实的 AMD AI PC 使用场景。目前后台主要部署两款设备：</p><table tabindex="0"><thead><tr><th>设备</th><th>定位</th><th>CPU</th><th>GPU（iGPU）</th><th>NPU</th></tr></thead><tbody><tr><td><strong>Ryzen™ AI Max+ 395</strong>（Strix Halo）</td><td>旗舰端侧 APU</td><td>Zen 5 · 16 核</td><td>Radeon™ 8060S（RDNA 3.5 · 40 CU）</td><td>XDNA™ 2 · ~50 TOPS</td></tr><tr><td><strong>Ryzen™ AI 9 HX 370</strong>（Strix Point）</td><td>高性能端侧 APU</td><td>Zen 5 · 12 核</td><td>Radeon™ 890M（RDNA 3.5 · 16 CU）</td><td>XDNA™ 2 · ~50 TOPS</td></tr></tbody></table><ul><li><strong>CPU</strong>：基于 Zen 5 架构，承担数据预处理、编译与常规计算任务。</li><li><strong>GPU（iGPU）</strong>：RDNA 3.5 集成显卡，通过 <strong>ROCm</strong> 为 PyTorch 等框架提供 GPU 加速。</li><li><strong>NPU</strong>：XDNA 2 架构 AI 引擎，面向低功耗端侧推理。</li></ul><h2 id="🚀-立即体验" tabindex="-1">🚀 立即体验 <a class="header-anchor" href="#🚀-立即体验" aria-label="Permalink to &quot;🚀 立即体验&quot;">​</a></h2><div align="center"><p><a href="https://tpe.aupcloud.io" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/%F0%9F%9A%80_AUP_Learning_Cloud-立即登录-ed1941?logo=amd&amp;logoColor=white&amp;labelColor=1a1a1a&amp;style=for-the-badge" height="44"></a></p><p>🔗 <a href="https://tpe.aupcloud.io" target="_blank" rel="noreferrer">https://tpe.aupcloud.io</a></p></div><h2 id="一、什么是-jupyterhub-code-server" tabindex="-1">一、什么是 JupyterHub / Code Server？ <a class="header-anchor" href="#一、什么是-jupyterhub-code-server" aria-label="Permalink to &quot;一、什么是 JupyterHub / Code Server？&quot;">​</a></h2><table tabindex="0"><thead><tr><th>JupyterHub</th><th>Code Server（VSCode Server）</th></tr></thead><tbody><tr><td>基于浏览器的远程开发平台：<br>- ✅ 浏览器直接写代码（无需本地配置环境）<br>- ✅ 使用 Python / Jupyter Notebook 实验与学习<br>- ✅ 代码文件保存在服务器，不怕电脑重装<br>- ✅ 在不同电脑上随时继续学习<br><br>📌 <strong>你只需要</strong>：一台能上网的电脑 + 现代浏览器（推荐 Chrome / Edge / Firefox）</td><td>在浏览器中运行的<strong>完整 VSCode 编辑器</strong>，可理解为「在浏览器里打开一个和本地一模一样的 VSCode」：<br>- ✅ 完整 VSCode 编辑体验（语法高亮、自动补全、调试）<br>- ✅ 终端中运行程序、脚本和训练任务<br>- ✅ 安装 VSCode 插件（Python、Jupyter、GitLens 等）<br>- ✅ 端口转发预览 Web 应用<br>- ✅ 适合需要 IDE 级开发体验的用户</td></tr></tbody></table><h2 id="二、登录说明" tabindex="-1">二、登录说明 <a class="header-anchor" href="#二、登录说明" aria-label="Permalink to &quot;二、登录说明&quot;">​</a></h2><h3 id="_1-获取-github-授权-本地账号密码" tabindex="-1">1. 获取 GitHub 授权 / 本地账号密码 <a class="header-anchor" href="#_1-获取-github-授权-本地账号密码" aria-label="Permalink to &quot;1. 获取 GitHub 授权 / 本地账号密码&quot;">​</a></h3><ul><li><strong>GitHub 授权登录</strong>：点击授权登录即可。</li><li><strong>本地账户</strong>：由管理员提供账号密码。</li></ul><h3 id="_2-打开登录页面" tabindex="-1">2. 打开登录页面 <a class="header-anchor" href="#_2-打开登录页面" aria-label="Permalink to &quot;2. 打开登录页面&quot;">​</a></h3><p>在浏览器地址栏输入：<a href="https://tpe.aupcloud.io" target="_blank" rel="noreferrer">https://tpe.aupcloud.io</a></p><div align="center"><img src="'+n+'" alt="AUP Learning Cloud 登录页面"></div><h3 id="_3-选择登录方式" tabindex="-1">3. 选择登录方式 <a class="header-anchor" href="#_3-选择登录方式" aria-label="Permalink to &quot;3. 选择登录方式&quot;">​</a></h3><p>平台提供两种登录方式：<strong>GitHub 账户登录（推荐）</strong> 和 <strong>本地账户登录</strong>（本地账户需管理员提供）。</p><div align="center"><img src="'+o+'" alt="选择登录方式"></div><h4 id="方式-1-github-账户登录-推荐" tabindex="-1">方式 1：GitHub 账户登录（推荐） <a class="header-anchor" href="#方式-1-github-账户登录-推荐" aria-label="Permalink to &quot;方式 1：GitHub 账户登录（推荐）&quot;">​</a></h4><ol><li>点击 <strong>Use GitHub Login</strong> 按钮</li><li>跳转到 GitHub 授权页面，选择已授权的 GitHub 账户</li></ol><div align="center"><img src="'+i+'" alt="GitHub 账户授权登录"></div><h4 id="方式-2-本地账户登录" tabindex="-1">方式 2：本地账户登录 <a class="header-anchor" href="#方式-2-本地账户登录" aria-label="Permalink to &quot;方式 2：本地账户登录&quot;">​</a></h4><p>从邮件中获取账号密码：</p><ol><li>在登录框中输入 <strong>Username</strong> 与 <strong>Password</strong></li><li>点击 <strong>Use LocalAccount Login</strong> 按钮，<strong>首次登录需要修改密码</strong></li></ol><h3 id="_4-成功登录后的界面" tabindex="-1">4. 成功登录后的界面 <a class="header-anchor" href="#_4-成功登录后的界面" aria-label="Permalink to &quot;4. 成功登录后的界面&quot;">​</a></h3><div align="center"><img src="'+l+'" alt="登录成功后的 JupyterHub 界面"></div><div align="center"><img src="'+d+'" alt="JupyterHub 启动服务器界面"></div><h2 id="三、平台使用须知与可用资源" tabindex="-1">三、平台使用须知与可用资源 <a class="header-anchor" href="#三、平台使用须知与可用资源" aria-label="Permalink to &quot;三、平台使用须知与可用资源&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">使用须知</p><ul><li><strong>运行时长</strong>：容器默认时长为 <strong>20 min</strong>，开启后左下角会有倒计时，倒计时结束会自动关闭容器。</li><li><strong>个人存储</strong>：每人默认存储空间为 <strong>20 G</strong>，无法存储超过该容量的文件。</li><li><strong>积分计费</strong>：消耗 = 运行时长（分钟）× 硬件倍率，会话结束时扣除；余额不足将无法启动新会话（倍率见下表）。</li></ul></div><table tabindex="0"><thead><tr><th>硬件</th><th>积分倍率</th></tr></thead><tbody><tr><td>CPU</td><td>1×</td></tr><tr><td>GPU（Radeon 8060S iGPU）</td><td>3×</td></tr></tbody></table><p><strong>可用资源目录</strong>：</p><ul><li><strong>Course</strong>（课程资料）：Computer Vision Course、Deep Learning Course、HIP Programming Course、Large Language Models Course、Genesis Physical Simulation Course（均提供 ROCm 7.13.0 版本）</li><li><strong>Development</strong>（开发环境）：Code Server CPU Environment、Code Server GPU Environment</li><li><strong>Test</strong>（测试环境）：HIP and ROCm Notebook Test</li><li><strong>Tutorial</strong>（教程内容）：Introduction to HIP</li><li><strong>Custom Repo</strong>（自定义仓库，提供基础镜像）：Basic Python Environment、Basic GPU Environment</li></ul><div align="center"><img src="'+p+'" alt="可用资源目录"></div><div align="center"><img src="'+h+`" alt="可用资源目录（资源类别）"></div><div class="warning custom-block"><p class="custom-block-title">注意</p><p>选择合适的镜像时长，计时结束时会关闭连接；未放置在用户存储目录 <code>/home/jovyan</code> 的内容会被重置。</p></div><h2 id="四、jupyterhub-使用说明" tabindex="-1">四、JupyterHub 使用说明 <a class="header-anchor" href="#四、jupyterhub-使用说明" aria-label="Permalink to &quot;四、JupyterHub 使用说明&quot;">​</a></h2><h3 id="_1-新建一个-notebook" tabindex="-1">1. 新建一个 Notebook <a class="header-anchor" href="#_1-新建一个-notebook" aria-label="Permalink to &quot;1. 新建一个 Notebook&quot;">​</a></h3><ol><li>选择 <strong>Python 3</strong></li><li>浏览器会打开一个新的 Notebook 页面</li></ol><p>🎉 恭喜，你已经可以开始写代码了！</p><h3 id="_2-运行代码" tabindex="-1">2. 运行代码 <a class="header-anchor" href="#_2-运行代码" aria-label="Permalink to &quot;2. 运行代码&quot;">​</a></h3><ul><li>在代码单元格中输入代码</li><li>按 <strong>Shift + Enter</strong> 运行当前单元</li><li>运行结果会显示在下方</li></ul><div class="language-python vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">print</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">(</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;Hello, JupyterHub!&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_3-保存你的工作" tabindex="-1">3. 保存你的工作 <a class="header-anchor" href="#_3-保存你的工作" aria-label="Permalink to &quot;3. 保存你的工作&quot;">​</a></h3><ul><li>JupyterHub <strong>会自动保存</strong>，也可手动保存：<code>Ctrl + S</code>（Windows）/ <code>Cmd + S</code>（Mac）</li><li>每个镜像的默认工作目录为 <code>/ryzers/notebooks</code>，用户拥有 20 G 磁盘的目录在 <code>/home/jovyan</code>。<strong>如需保存工作内容，请在镜像结束前迁移至 <code>/home/jovyan</code>。</strong></li></ul><p>⚠️ 默认工作目录：<code>/ryzers/notebooks</code>　　⚠️ 用户存档目录：<code>/home/jovyan</code></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#008000;--shiki-dark:#6A9955;"># 切换 bash</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">bash</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">cp</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> &lt;</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">需要保存的文</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">件&gt; </span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">/home/jovyan</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="五、code-server-vscode-server-使用说明" tabindex="-1">五、Code Server（VSCode Server）使用说明 <a class="header-anchor" href="#五、code-server-vscode-server-使用说明" aria-label="Permalink to &quot;五、Code Server（VSCode Server）使用说明&quot;">​</a></h2><h3 id="_1-启动-code-server-环境" tabindex="-1">1. 启动 Code Server 环境 <a class="header-anchor" href="#_1-启动-code-server-环境" aria-label="Permalink to &quot;1. 启动 Code Server 环境&quot;">​</a></h3><ol><li>登录后，在启动页面选择 <strong>Code Server CPU Environment</strong> 或 <strong>Code Server GPU Environment</strong></li><li>选择所需的硬件配置（如 AMD Radeon™ 8060S GPU）</li></ol><div align="center"><img src="`+c+'" alt="选择 Code Server 环境"></div><ol start="3"><li>设置运行时长，点击 <strong>Launch Server</strong></li><li>等待几秒后，浏览器将自动打开 VSCode 界面</li></ol><div align="center"><img src="'+u+`" alt="Code Server 启动配置页面"></div><h3 id="_2-界面介绍" tabindex="-1">2. 界面介绍 <a class="header-anchor" href="#_2-界面介绍" aria-label="Permalink to &quot;2. 界面介绍&quot;">​</a></h3><p>Code Server 的界面和本地 VSCode <strong>完全一致</strong>：</p><ul><li><strong>左侧</strong>：文件资源管理器、搜索、源代码管理、调试、扩展</li><li><strong>中间</strong>：代码编辑区域</li><li><strong>下方</strong>：集成终端（Terminal）、端口面板（Ports）、输出面板</li></ul><h3 id="_3-端口转发-port-forwarding" tabindex="-1">3. 端口转发（Port Forwarding） <a class="header-anchor" href="#_3-端口转发-port-forwarding" aria-label="Permalink to &quot;3. 端口转发（Port Forwarding）&quot;">​</a></h3><p>当你在 Code Server 中运行一个 Web 服务（如 Node.js、Flask、Streamlit 等），系统会<strong>自动检测并转发端口</strong>。</p><p><strong>使用方法</strong>：</p><ol><li>在终端中启动服务，例如：</li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">node</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> test.js</span></span>
<span class="line"><span style="--shiki-light:#008000;--shiki-dark:#6A9955;"># 输出: Running on port: 3000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ol start="2"><li>右下角会弹出通知提示端口已转发，点击 <strong>Open in Browser</strong> 即可在新标签页访问</li></ol><div align="center"><img src="`+g+'" alt="端口转发通知"></div><ol start="3"><li>也可以在底部 <strong>PORTS</strong> 面板中查看所有已转发的端口</li></ol><div align="center"><img src="'+b+'" alt="PORTS 端口面板"></div><p><strong>转发地址格式</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>https://tpe.aupcloud.io/user/&lt;your-username&gt;/proxy/&lt;port&gt;/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>例如：<code>https://tpe.aupcloud.io/user/github%3Ausername/proxy/3000/</code></p><div align="center"><img src="'+m+'" alt="端口转发地址示例"></div><p><strong>注意事项</strong>：</p><ul><li>端口转发是<strong>自动</strong>的，无需手动配置</li><li>支持任何在服务器上监听端口的服务（HTTP / WebSocket）</li><li>转发地址可以分享给他人访问（在同一网络授权下）</li><li>如果端口未自动检测，可在 PORTS 面板手动添加</li></ul><h3 id="_4-插件-extensions-使用" tabindex="-1">4. 插件（Extensions）使用 <a class="header-anchor" href="#_4-插件-extensions-使用" aria-label="Permalink to &quot;4. 插件（Extensions）使用&quot;">​</a></h3><p>Code Server 支持安装 VSCode 插件来增强开发体验。</p><p><strong>已预装的插件</strong>：</p><table tabindex="0"><thead><tr><th>插件</th><th>用途</th></tr></thead><tbody><tr><td>Python</td><td>Python 语言支持、IntelliSense、调试</td></tr><tr><td>Jupyter</td><td>在 VSCode 中运行 Jupyter Notebook</td></tr><tr><td>GitLens</td><td>Git 增强（查看 blame、历史、对比）</td></tr><tr><td>Python Debugger</td><td>Python 断点调试</td></tr><tr><td>Ruff</td><td>Python 代码格式化和 lint</td></tr><tr><td>YAML</td><td>YAML 文件语法支持</td></tr></tbody></table><p><strong>安装新插件</strong>：</p><ol><li>点击左侧<strong>扩展图标</strong>（四方块形状）</li><li>在搜索框输入插件名称</li><li>点击 <strong>Install</strong> 安装</li></ol><div align="center"><img src="'+k+`" alt="安装新插件"></div><p><strong>推荐安装的插件</strong>：C/C++（配合 HIP 开发）、ROCm HIP（AMD GPU 编程支持）、Remote - Containers、Thunder Client、Markdown Preview。</p><div class="warning custom-block"><p class="custom-block-title">注意</p><ul><li>插件安装在服务器端，<strong>镜像重启后需要重新安装</strong>。</li><li>建议将常用插件列表记录下来，方便下次快速安装。</li><li>部分插件可能因网络原因安装失败，可尝试刷新页面后重试。</li></ul></div><h3 id="_5-终端-terminal-使用" tabindex="-1">5. 终端（Terminal）使用 <a class="header-anchor" href="#_5-终端-terminal-使用" aria-label="Permalink to &quot;5. 终端（Terminal）使用&quot;">​</a></h3><p>在 Code Server 中可以直接使用集成终端：</p><ul><li>快捷键 <code>Ctrl + \`</code> 打开/关闭终端</li><li>支持多终端窗口（点击 + 号新建）</li><li>默认 shell 为 bash</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#008000;--shiki-dark:#6A9955;"># 查看 GPU 状态</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">rocm-smi</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#008000;--shiki-dark:#6A9955;"># 安装 Python 包</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">pip</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> install</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> torch</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> torchvision</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#008000;--shiki-dark:#6A9955;"># 运行训练脚本</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">python</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> train.py</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#008000;--shiki-dark:#6A9955;"># 启动 Web 服务（会自动端口转发）</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">python</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> -m</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> http.server</span><span style="--shiki-light:#098658;--shiki-dark:#B5CEA8;"> 8080</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="六、正确退出方式-很重要" tabindex="-1">六、正确退出方式（很重要） <a class="header-anchor" href="#六、正确退出方式-很重要" aria-label="Permalink to &quot;六、正确退出方式（很重要）&quot;">​</a></h2><p>使用完成后，请<strong>正确退出</strong>：</p><ol><li>打开菜单 <strong>File → Hub Control Panel</strong>（见下图），在控制面板中点击 <strong>Stop My Server</strong> 停止服务器，然后关闭浏览器标签页。</li></ol><p>⚠️ 不要长时间占用服务器资源！</p><div align="center"><img src="`+v+'" alt="File → Hub Control Panel 退出入口"></div><p><strong>VSCode Server GPU：如何回到主页</strong></p><p>在 Code Server（VSCode Server）环境中，若要退出或切换镜像，需先回到 JupyterHub 主页：点击<strong>左下角状态栏的 JupyterHub 按钮</strong>（见下图红色箭头处），即可返回 Hub 主页，随后按上文点击 <strong>Stop My Server</strong> 停止服务器。</p><div align="center"><img src="'+C+'" alt="Code Server 左下角 JupyterHub 按钮回到主页"></div><h2 id="七、常见问题答疑-faq" tabindex="-1">七、常见问题答疑（FAQ） <a class="header-anchor" href="#七、常见问题答疑-faq" aria-label="Permalink to &quot;七、常见问题答疑（FAQ）&quot;">​</a></h2><p><strong>Q1：页面打不开 / 加载很慢怎么办？</strong> 检查网络是否正常；尝试更换浏览器（推荐 Chrome / Edge）；刷新页面或重新登录。</p><p><strong>Q2：已经启用一个镜像，想换另一个镜像，无法启动？</strong> 请在选择界面点击 <strong>Stop my server</strong> 关闭当前镜像后再启动新镜像。</p><div align="center"><img src="'+y+'" alt="Stop my server 关闭当前镜像"></div><p><strong>Q3：代码报错了，是平台的问题吗？</strong> 大多数情况下不是。请先检查：是否有拼写错误、是否漏写括号或冒号、是否按顺序运行了所有单元。</p><p><strong>Q4：Code Server 中端口转发不生效？</strong> 确认服务确实在监听该端口（终端能看到 <code>Running on port: XXXX</code>）；检查 PORTS 面板是否有对应端口记录；尝试手动在 PORTS 面板添加端口；仍不生效则刷新浏览器页面。</p><p><strong>Q5：Code Server 中插件安装失败？</strong> 检查网络连接是否正常；尝试刷新页面后重新安装；部分插件可能不兼容 Code Server（web 版），可尝试搜索替代插件。</p><h2 id="八、使用小建议-强烈推荐" tabindex="-1">八、使用小建议（强烈推荐） <a class="header-anchor" href="#八、使用小建议-强烈推荐" aria-label="Permalink to &quot;八、使用小建议（强烈推荐）&quot;">​</a></h2><ul><li>⭐ 经常保存代码</li><li>⭐ 文件命名清晰（不要用 <code>test123.ipynb</code>）</li><li>⭐ 不要在一个 Notebook 里写「所有内容」</li><li>⭐ 遇到问题及时提问，不要憋着</li><li>⭐ 重要文件记得存到 <code>/home/jovyan</code> 目录</li><li>⭐ Code Server 用户建议记录常用插件列表，方便重装</li></ul><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><strong>AUP Learning Cloud 开源仓库</strong>（AMD Research · MIT 许可）：<a href="https://github.com/AMDResearch/aup-learning-cloud" target="_blank" rel="noreferrer">https://github.com/AMDResearch/aup-learning-cloud</a></li><li><strong>AUP Learning Cloud 项目文档</strong>：<a href="https://amdresearch.github.io/aup-learning-cloud/" target="_blank" rel="noreferrer">https://amdresearch.github.io/aup-learning-cloud/</a></li></ul><hr><p>返回：<a href="/hello-rocm/zh/">← hello-rocm 首页</a></p>',107)])])}const H=t(P,[["render",_]]);export{x as __pageData,H as default};
